 13→func TestPreferencesJSON_RoundTrip(t *testing.T) {
 14→	t.Parallel()
 15→	lat := 40.7128
 16→	lng := -74.006
 17→	state := "NY"
 18→	prefs := Preferences{
 19→		HomeLatitude:  &lat,
 20→		HomeLongitude: &lng,
 21→		HomeState:     &state,
 22→	}
 23→
 24→	data, err := json.Marshal(prefs)
 25→	if err != nil {
 26→		t.Fatalf("marshal failed: %v", err)
 27→	}
 28→
 29→	var got Preferences
 30→	if err := json.Unmarshal(data, &got); err != nil {
 31→		t.Fatalf("unmarshal failed: %v", err)
 32→	}
 33→
 34→	if got.HomeLatitude == nil || *got.HomeLatitude != lat {
 35→		t.Errorf("HomeLatitude = %v, want %v", got.HomeLatitude, lat)
 36→	}
