 65→// ensureTestUser creates a user+team via user.Service and returns the team ID.
 66→func ensureTestUser(t *testing.T, ctx context.Context, pool *pgxpool.Pool, userSvc *user.Service, userID, email string) string {
 67→	t.Helper()
 68→	if err := userSvc.EnsureUser(ctx, userID, email); err != nil {
 69→		t.Fatalf("EnsureUser failed: %v", err)
 70→	}
 71→	var teamID string
