129→func TestIntegrationUpdate_Upsert(t *testing.T) {
130→	pool := testdb.New(t)
131→	ctx := context.Background()
132→	userSvc := user.NewService(pool)
133→	svc := NewService(pool)
134→
135→	teamID := ensureTestUser(t, ctx, pool, userSvc, "pref-user-003", "test3@example.com")
136→
137→	lat1 := 40.7128
138→	lng1 := -74.006
139→	state1 := "NY"
140→	_, err := svc.Update(ctx, teamID, &Preferences{
141→		HomeLatitude:  &lat1,
142→		HomeLongitude: &lng1,
143→		HomeState:     &state1,
144→	})
145→	if err != nil {
146→		t.Fatalf("first Update failed: %v", err)
147→	}
148→
149→	// Update to new values
150→	lat2 := 41.8781
151→	lng2 := -87.6298
152→	state2 := "IL"
153→	result, err := svc.Update(ctx, teamID, &Preferences{
154→		HomeLatitude:  &lat2,
155→		HomeLongitude: &lng2,
156→		HomeState:     &state2,
157→	})
158→	if err != nil {
159→		t.Fatalf("second Update failed: %v", err)
160→	}
161→	if result.HomeLatitude == nil || *result.HomeLatitude != lat2 {
162→		t.Errorf("HomeLatitude = %v, want %v", result.HomeLatitude, lat2)
163→	}
164→	if result.HomeState == nil || *result.HomeState != state2 {
165→		t.Errorf("HomeState = %v, want %v", result.HomeState, state2)
166→	}
167→
168→	// Verify Get returns updated values
169→	got, err := svc.Get(ctx, teamID)
170→	if err != nil {
171→		t.Fatalf("Get failed: %v", err)
172→	}
173→	if got.HomeLatitude == nil || *got.HomeLatitude != lat2 {
174→		t.Errorf("Get HomeLatitude = %v, want %v", got.HomeLatitude, lat2)
175→	}
176→}
