import { create } from 'zustand'
import { graphql } from 'gql.tada'
import { urqlClient } from '@/lib/urqlClient'

const PreferencesQuery = graphql(`
  query Preferences {
    preferences {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`)

const UpdatePreferencesMutation = graphql(`
  mutation UpdatePreferences($input: UpdatePreferencesInput!) {
    updatePreferences(input: $input) {
      homeLatitude
      homeLongitude
      homeState
    }
  }
`)

interface PreferencesData {
  homeLatitude: number | null
  homeLongitude: number | null
  homeState: string | null
}

interface PreferencesState extends PreferencesData {
  loaded: boolean
  loading: boolean

  load: () => Promise<void>
  update: (prefs: Partial<PreferencesData>) => Promise<void>
  clear: () => void
}

export const usePreferencesStore = create<PreferencesState>()((set, get) => ({
  homeLatitude: null,
  homeLongitude: null,
  homeState: null,
  loaded: false,
  loading: false,

  load: async () => {
    if (get().loaded || get().loading) return
    set({ loading: true })
    try {
      const result = await urqlClient
        .query<{ preferences: PreferencesData }>(PreferencesQuery, {})
        .toPromise()
      if (result.data?.preferences) {
        const { homeLatitude, homeLongitude, homeState } = result.data.preferences
        set({
          homeLatitude: homeLatitude ?? null,
          homeLongitude: homeLongitude ?? null,
          homeState: homeState ?? null,
          loaded: true,
        })
      }
    } finally {
      set({ loading: false })
    }
  },

  update: async (prefs) => {
    const result = await urqlClient
      .mutation<{ updatePreferences: PreferencesData }>(UpdatePreferencesMutation, { input: prefs })
      .toPromise()
    if (result.data?.updatePreferences) {
      const { homeLatitude, homeLongitude, homeState } = result.data.updatePreferences
      set({
        homeLatitude: homeLatitude ?? null,
        homeLongitude: homeLongitude ?? null,
        homeState: homeState ?? null,
      })
    }
  },

  clear: () => {
    set({
      homeLatitude: null,
      homeLongitude: null,
      homeState: null,
      loaded: false,
      loading: false,
    })
  },
}))

import { useState, useCallback } from 'react'
import { graphql } from 'gql.tada'
import { useQuery } from '@/lib/graphql'
import { TextInput, Group, Text, Stack } from '@mantine/core'
import { Button } from '@/components/ui/button'
import { MapPin, X, Loader2 } from 'lucide-react'

export interface UserLocationValue {
  latitude: number
  longitude: number
  state?: string
  displayName?: string
}

const ResolveZipQuery = graphql(`
  query ResolveZip($zip: String!) {
    resolveZip(zip: $zip) {
      zip
      latitude
      longitude
      state
      city
    }
  }
`)

export interface LocationInputProps {
  value: UserLocationValue | undefined
  onChange: (loc: UserLocationValue | undefined) => void
}

export function LocationInput({ value, onChange }: LocationInputProps) {
  const [zipInput, setZipInput] = useState('')
  const [zipError, setZipError] = useState<string | undefined>()
  const [geoLoading, setGeoLoading] = useState(false)

  const zipToResolve = /^\d{5}$/.test(zipInput) ? zipInput : null

  const [zipResult] = useQuery<{
    resolveZip: { zip: string; latitude: number; longitude: number; state: string; city: string } | null
  }>({
    query: ResolveZipQuery,
    variables: { zip: zipToResolve ?? '' },
    pause: !zipToResolve,
  })

  const handleZipSubmit = useCallback(() => {
    if (!/^\d{5}$/.test(zipInput)) {
      setZipError('Enter a 5-digit ZIP code')
      return
    }
    setZipError(undefined)

    if (zipResult.data?.resolveZip) {
      const z = zipResult.data.resolveZip
      onChange({
        latitude: z.latitude,
        longitude: z.longitude,
        state: z.state,
        displayName: `${z.city}, ${z.state}`,
      })
    } else if (zipResult.fetching) {
      // Wait for result — user will need to submit again
      setZipError('Looking up ZIP code…')
    } else {
      setZipError('ZIP code not found')
    }
  }, [zipInput, zipResult, onChange])

  const handleGeolocation = useCallback(() => {
    if (!navigator.geolocation) {
      setZipError('Geolocation not supported')
      return
    }
    setGeoLoading(true)
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setGeoLoading(false)
        onChange({
          latitude: pos.coords.latitude,
          longitude: pos.coords.longitude,
          displayName: `${pos.coords.latitude.toFixed(2)}°, ${pos.coords.longitude.toFixed(2)}°`,
        })
      },
      () => {
        setGeoLoading(false)
        setZipError('Could not get your location')
      },
    )
  }, [onChange])

  const handleClear = useCallback(() => {
    onChange(undefined)
    setZipInput('')
    setZipError(undefined)
  }, [onChange])

  if (value) {
    return (
      <Group gap="xs">
        <MapPin size={14} />
        <Text size="sm" fw={500}>
          {value.displayName ?? `${value.latitude.toFixed(2)}°, ${value.longitude.toFixed(2)}°`}
        </Text>
        <Button variant="ghost" size="compact-xs" onClick={handleClear} aria-label="Clear location">
          <X size={12} />
        </Button>
      </Group>
    )
  }

  return (
    <Stack gap="xs">
      <Group gap="xs" align="flex-end">
        <TextInput
          label="ZIP code"
          placeholder="e.g. 02134"
          value={zipInput}
          onChange={(e) => {
            setZipInput(e.currentTarget.value)
            setZipError(undefined)
          }}
          onKeyDown={(e) => {
            if (e.key === 'Enter') handleZipSubmit()
          }}
          error={zipError}
          size="xs"
          style={{ flex: 1 }}
        />
        <Button variant="default" size="xs" onClick={handleZipSubmit} disabled={zipResult.fetching}>
          Go
        </Button>
      </Group>
      <Button
        variant="light"
        size="xs"

        leftSection={geoLoading ? <Loader2 size={14} /> : <MapPin size={14} />}
        onClick={handleGeolocation}
        disabled={geoLoading}
      >
        Use my location
      </Button>
    </Stack>
  )
}

import { describe, it, expect, vi, beforeEach } from 'vitest'

const mockQuery = vi.fn()
const mockMutation = vi.fn()

vi.mock('@/lib/urqlClient', () => ({
  urqlClient: {
    query: (...args: unknown[]) => ({ toPromise: () => mockQuery(...args) }),
    mutation: (...args: unknown[]) => ({ toPromise: () => mockMutation(...args) }),
  },
}))

describe('preferencesStore', () => {
  beforeEach(async () => {
    vi.resetModules()
    mockQuery.mockReset()
    mockMutation.mockReset()
  })

  async function getStore() {
    const { usePreferencesStore } = await import('./preferencesStore')
    return usePreferencesStore
  }

  it('has correct initial state', async () => {
    const store = await getStore()
    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })

  it('load fetches and stores preferences', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: {
          homeLatitude: 40.7128,
          homeLongitude: -74.006,
          homeState: 'NY',
        },
      },
    })
    const store = await getStore()

    await store.getState().load()

    const state = store.getState()
    expect(state.homeLatitude).toBe(40.7128)
    expect(state.homeLongitude).toBe(-74.006)
    expect(state.homeState).toBe('NY')
    expect(state.loaded).toBe(true)
    expect(state.loading).toBe(false)
  })

  it('load skips if already loaded', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: 40.7, homeLongitude: -74.0, homeState: 'NY' },
      },
    })
    const store = await getStore()

    await store.getState().load()
    await store.getState().load()

    expect(mockQuery).toHaveBeenCalledOnce()
  })

  it('load handles null preferences gracefully', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: null, homeLongitude: null, homeState: null },
      },
    })
    const store = await getStore()

    await store.getState().load()

    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(true)
  })

  it('update sends mutation and updates state', async () => {
    mockMutation.mockResolvedValue({
      data: {
        updatePreferences: {
          homeLatitude: 34.05,
          homeLongitude: -118.24,
          homeState: 'CA',
        },
      },
    })
    const store = await getStore()

    await store.getState().update({
      homeLatitude: 34.05,
      homeLongitude: -118.24,
      homeState: 'CA',
    })

    const state = store.getState()
    expect(state.homeLatitude).toBe(34.05)
    expect(state.homeLongitude).toBe(-118.24)
    expect(state.homeState).toBe('CA')
  })

  it('clear resets all state', async () => {
    mockQuery.mockResolvedValue({
      data: {
        preferences: { homeLatitude: 40.7, homeLongitude: -74.0, homeState: 'NY' },
      },
    })
    const store = await getStore()

    await store.getState().load()
    store.getState().clear()

    const state = store.getState()
    expect(state.homeLatitude).toBeNull()
    expect(state.homeLongitude).toBeNull()
    expect(state.homeState).toBeNull()
    expect(state.loaded).toBe(false)
    expect(state.loading).toBe(false)
  })
})

