        <Stack gap="xs">
          <Text size="sm" fw={500}>
            Home location
          </Text>
          <LocationInput value={location} onChange={handleLocationChange} />
        </Stack>

        <Select
          label="Home state"
          placeholder="Select a state"
          data={US_STATES}
          value={state}
          onChange={setState}
          searchable
          clearable
        />

        {feedback && (
          <Alert
            color={feedback.type === 'success' ? 'green' : 'red'}
            variant="light"
          >
            {feedback.message}
          </Alert>
        )}

        <Group justify="space-between">
          <Button
            variant="light"
            size="xs"
            onClick={() => void handleClear()}
            disabled={saving || !hasPreferences}
          >
            Clear all
          </Button>
          <Group gap="xs">
            <Button variant="outline" size="xs" onClick={onClose}>
              Cancel
            </Button>
            <Button
              variant="accent"
              size="xs"
              onClick={() => void handleSave()}
              disabled={saving}
              leftSection={<MapPin size={14} />}
            >
              {saving ? 'Saving...' : 'Save'}
            </Button>
          </Group>
        </Group>
      </Stack>
    </Modal>
  )
}

