import { describe, it, expect, vi, beforeEach } from 'vitest'
import { screen, fireEvent, waitFor } from '@testing-library/react'
import { renderWithMantine } from '@/test/render'
import { PreferencesModal } from './PreferencesModal'

// Mock the preferences store
const mockLoad = vi.fn()
const mockUpdate = vi.fn()

let mockStoreState = {
  homeLatitude: null as number | null,
  homeLongitude: null as number | null,
  homeState: null as string | null,
  loaded: false,
  loading: false,
  load: mockLoad,
  update: mockUpdate,
  clear: vi.fn(),
}

vi.mock('@/stores/preferencesStore', () => ({
  usePreferencesStore: (selector: (s: typeof mockStoreState) => unknown) => selector(mockStoreState),
}))

// Mock LocationInput to simplify testing
vi.mock('@/components/search/LocationInput', () => ({
  LocationInput: ({
    value,
    onChange,
  }: {
    value: { latitude: number; longitude: number } | undefined
    onChange: (v: { latitude: number; longitude: number; state: string } | undefined) => void
  }) => (
    <div data-testid="location-input">
      {value ? (
        <>
          <span data-testid="location-display">
            {value.latitude}, {value.longitude}
          </span>
          <button data-testid="location-clear" onClick={() => onChange(undefined)}>
            Clear
          </button>
        </>
      ) : (
        <button
          data-testid="location-set"
          onClick={() => onChange({ latitude: 40.71, longitude: -74.01, state: 'NY' })}
        >
          Set location
        </button>
      )}
    </div>
  ),
}))

// Mock urql hooks used by LocationInput's ResolveZipQuery
vi.mock('urql', () => ({
  useQuery: () => [{ data: null, fetching: false }],
}))

describe('PreferencesModal', () => {
  beforeEach(() => {
    vi.clearAllMocks()
    mockStoreState = {
      homeLatitude: null,
      homeLongitude: null,
      homeState: null,
      loaded: false,
      loading: false,
      load: mockLoad,
      update: mockUpdate,
      clear: vi.fn(),
    }
  })

  it('calls load when opened', () => {
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)
    expect(mockLoad).toHaveBeenCalled()
  })

  it('does not render content when closed', () => {
    renderWithMantine(<PreferencesModal opened={false} onClose={vi.fn()} />)
    expect(screen.queryByText('Preferences')).not.toBeInTheDocument()
  })

  it('renders with empty state when no preferences loaded', () => {
    mockStoreState.loaded = true
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    expect(screen.getByText('Home location')).toBeInTheDocument()
    expect(screen.getByText('Save')).toBeInTheDocument()
    expect(screen.getByText('Clear all')).toBeInTheDocument()
    expect(screen.getByText('Cancel')).toBeInTheDocument()
  })

  it('shows existing location when preferences are loaded', () => {
    mockStoreState = {
      ...mockStoreState,
      homeLatitude: 40.71,
      homeLongitude: -74.01,
      homeState: 'NY',
      loaded: true,
    }
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    expect(screen.getByTestId('location-display')).toHaveTextContent('40.71, -74.01')
  })

  it('calls update with location on save', async () => {
    mockStoreState.loaded = true
    mockUpdate.mockResolvedValue(undefined)
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    // Set a location via mock
    fireEvent.click(screen.getByTestId('location-set'))

    // Click save
    fireEvent.click(screen.getByText('Save'))

    await waitFor(() => {
      expect(mockUpdate).toHaveBeenCalledWith({
        homeLatitude: 40.71,
        homeLongitude: -74.01,
        homeState: 'NY',
      })
    })
  })

  it('shows success feedback after save', async () => {
    mockStoreState.loaded = true
    mockUpdate.mockResolvedValue(undefined)
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    fireEvent.click(screen.getByTestId('location-set'))
    fireEvent.click(screen.getByText('Save'))

    await waitFor(() => {
      expect(screen.getByText('Preferences saved.')).toBeInTheDocument()
    })
  })

  it('shows error feedback when save fails', async () => {
    mockStoreState.loaded = true
    mockUpdate.mockRejectedValue(new Error('network error'))
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    fireEvent.click(screen.getByTestId('location-set'))
    fireEvent.click(screen.getByText('Save'))

    await waitFor(() => {
      expect(screen.getByText('Failed to save preferences.')).toBeInTheDocument()
    })
  })

  it('calls update with nulls on clear', async () => {
    mockStoreState = {
      ...mockStoreState,
      homeLatitude: 40.71,
      homeLongitude: -74.01,
      homeState: 'NY',
      loaded: true,
    }
    mockUpdate.mockResolvedValue(undefined)
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    fireEvent.click(screen.getByText('Clear all'))

    await waitFor(() => {
      expect(mockUpdate).toHaveBeenCalledWith({
        homeLatitude: null,
        homeLongitude: null,
        homeState: null,
      })
    })
  })

  it('shows success feedback after clear', async () => {
    mockStoreState = {
      ...mockStoreState,
      homeLatitude: 40.71,
      homeLongitude: -74.01,
      homeState: 'NY',
      loaded: true,
    }
    mockUpdate.mockResolvedValue(undefined)
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    fireEvent.click(screen.getByText('Clear all'))

    await waitFor(() => {
      expect(screen.getByText('Preferences cleared.')).toBeInTheDocument()
    })
  })

  it('disables clear button when no preferences set', () => {
    mockStoreState.loaded = true
    renderWithMantine(<PreferencesModal opened={true} onClose={vi.fn()} />)

    const clearBtn = screen.getByText('Clear all').closest('button')
    expect(clearBtn).toBeDisabled()
  })

  it('calls onClose when cancel is clicked', () => {
    mockStoreState.loaded = true
    const onClose = vi.fn()
    renderWithMantine(<PreferencesModal opened={true} onClose={onClose} />)

    fireEvent.click(screen.getByText('Cancel'))
    expect(onClose).toHaveBeenCalled()
  })
})

